import java.util.Arrays;

public class Solution {
    public static long solve(long[] nums, long k) {
        int n = nums.length;
        if (n == 0) return 0;
        Arrays.sort(nums);
        long maxLen = 1;
        for (int i = 0; i < n; i++) {
            long target = nums[i] * k;
            int low = i;
            int high = n - 1;
            int j = i;
            while (low <= high) {
                int mid = (low + high) / 2;
                if (nums[mid] <= target) {
                    j = mid;
                    low = mid + 1;
                } else {
                    high = mid - 1;
                }
            }
            int currentLen = j - i + 1;
            if (currentLen > maxLen) {
                maxLen = currentLen;
            }
        }
        return n - maxLen;
    }
}
```

